				if (found)
				{
					return result;
				}
			}
			else
			{
				if (source is IList<TSource> list)
				{
					return list[index];
				}
				if (index >= 0)
				{
					using IEnumerator<TSource> enumerator = source.GetEnumerator();
					while (enumerator.MoveNext())
					{
						if (index == 0)
						{
							return enumerator.Current;
						}
						index--;
					}
				}
			}
			throw Error.ArgumentOutOfRange("index");
		}

