			_next = next;
		}

		internal override void ComputeKeys(TElement[] elements, int count)
		{
			_keys = new TKey[count];
			for (int i = 0; i < count; i++)
			{
				_keys[i] = _keySelector(elements[i]);
			}
			_next?.ComputeKeys(elements, count);
