			{
				WaitUntilNonFull();
			}
			int producerBufferIndex = _producerBufferIndex;
			_buffer[producerBufferIndex] = chunk;
			Interlocked.Exchange(ref _producerBufferIndex, (producerBufferIndex + 1) % _buffer.Length);
