			{
				_consumerIsWaiting = 0;
				_consumerEvent.Set(_index);
			}
		}

		private void WaitUntilNonFull()
		{
			do
			{
				_producerEvent.Reset();
				Interlocked.Exchange(ref _producerIsWaiting, 1);
