					}
					if (_consumerWaiting[_partitionIndex])
					{
						Monitor.Pulse(_bufferLock);
						_consumerWaiting[_partitionIndex] = false;
					}
					if (_buffers[_partitionIndex].Count >= 8192)
					{
						_producerWaiting[_partitionIndex] = true;
						Monitor.Wait(_bufferLock);
					}
				}
			}
			while (i == num);
		}

