		{
			if (type.IsNullableType())
			{
				Type nonNullableType = type.GetNonNullableType();
				if (il.TryEmitILConstant(value, nonNullableType))
				{
					il.Emit(OpCodes.Newobj, type.GetConstructor(new Type[1] { nonNullableType }));
